#pragma mark - route

- (void)jun_routeBuild:(JUNRouteBuilder *)route {

    [route name:@"popup" handle:^(NSDictionary * _Nullable userInfo, JUNRouterNextHandler  _Nonnull next) {
        if (userInfo[@"data"]) {
            NSDictionary *richMessagesData = [userInfo[@"data"] jsonValueDecoded];
            self.sourceInterface = userInfo[@"sourceInterface"];
            NSLog(@"richMessagesData = %@", richMessagesData);
            if (richMessagesData && [richMessagesData count] > 0) { // 检查 richMessagesData 是否非空且包含键值对
                WBPopupShowStatus status = [[WBPopupDecisionMaker sharedInstance] shouldShowPopup];
                switch (status) {
                    case WBPopupShowStatusShow:
                        // 正常展示弹窗
                        [self handleRichMessages:richMessagesData];
                        break;
                    case WBPopupShowStatusNotShow:
                        // 不展示弹窗，直接跳过
                        break;
                    case WBPopupShowStatusStore:
                        // 暂存弹窗数据，待相关事件（如开屏广告）结束后展示
                        [self storePopupDataForLater:richMessagesData];
                        break;
                    default:
                        break;
                }
            } else {
                // 如果 richMessagesData 为空，则不处理
                NSLog(@"route_popup: richMessagesData is empty, no popup will be shown.");
            }
            self.sourceInterface = nil;
        }
        next(nil);
    }];

    [route name:@"promoReceive" handle:^(NSDictionary * _Nullable userInfo, JUNRouterNextHandler  _Nonnull next) {
        NSString *promocodeId = userInfo[@"promocodeId"];
        NSLog(@"promocodeId = %@", promocodeId);

        if ([self.whichTogetPromo isEqual:@"static"]) {
            [WBCustomPopupViewController handlePromoReceiveWithPromoId:promocodeId];
        } else if ([self.whichTogetPromo isEqual:@"dynamic"]) {
            [WBDynamicPopupViewController handlePromoReceiveWithPromoId:promocodeId];
        }

        next(nil);
    }];

    [route name:@"rate" handle:^(NSDictionary * _Nullable userInfo, JUNRouterNextHandler  _Nonnull next) {
        self.stashedDefaultHandler = nil;
        NSString *type = userInfo[@"type"];
        if (type && [type isEqualToString:@"inapp"]) {
            if (@available(iOS 14.0, *)) {
                UIWindowScene *scene = (UIWindowScene *)[UIApplication sharedApplication].connectedScenes.allObjects[0];
                [WBEventManager logAppQuickRateEvent:[@(WBSettingManager.sharedManager.TrackId) stringValue] from:@"route"];
                [SKStoreReviewController requestReviewInScene:scene];
            }
            return;
        }
        [[WBAppManager sharedManager] writeReviewInAppStore:@"route"];
    }];

    [route name:@"closeVip" handle:^(NSDictionary * _Nullable userInfo, JUNRouterNextHandler  _Nonnull next) {
        [[NSNotificationCenter defaultCenter] postNotificationName:WBRouteCloseVIPNotification object:nil];
    }];

    [route name:@"exit" handle:^(NSDictionary * _Nullable userInfo, JUNRouterNextHandler  _Nonnull next) {
        exit(0);
    }];

    [route name:@"appleShare" handle:^(NSDictionary * _Nullable userInfo, JUNRouterNextHandler  _Nonnull next) {
        // pull share page
        [WBMineViewController shareApp];
    }];

    [route name:@"eventShareAppByWeChatFriends" handle:^(NSDictionary * _Nullable userInfo, JUNRouterNextHandler  _Nonnull next) {
        [[WBAppManager sharedManager] shareAppByWeChatFriends];
