                    UIAlertController *alert = [UIAlertController alertControllerWithTitle:@"温馨提示" message:@"打开消息推送需要在系统设置中开启通知权限" preferredStyle:UIAlertControllerStyleAlert];
                    [alert addAction:[UIAlertAction actionWithTitle:@"取消" style:UIAlertActionStyleCancel handler:^(UIAlertAction *action) {}]];

