- (void)installVApp:(WBVAppModel *)vapp {
    vapp.progress = 0.0;
    CFAbsoluteTime start = CFAbsoluteTimeGetCurrent();
    [self saveStatus:WBVappStatusInstalling forVApp:vapp];

    [[WBActionRequestManager sharedManager] requestReportEventWithType:WBActionRequestEventTypeVappInstalling defaultHandler:nil];

    [WBStorageManager.sharedManager unzipIPAForVapp:vapp progressHandler:^(long entryNumber, long total) {
        CGFloat progress = ((CGFloat)entryNumber)/(total+1);
        if (progress> 0.01+vapp.progress) {
            vapp.progress = progress;
            [vapp setInMemoryStatus:WBVappStatusInstalling];
            NSLog(@"unzipping ipa: %f", progress);
        }
    } completionHandler:^(NSString * path, BOOL succeeded, NSError * error) {
        if (succeeded) {
            NSLog(@"Install: success unziped at %@", path);
            NSString *user = vapp.userInfo.user;
            NSString *bundleId = vapp.bundleId;
            [WBEventManager logVappInstallEvent:vapp];
            OAAErr result;
            NSString *version;
            if (!user) {
                version = vapp.versionInfo.version;
                result = oaa_install_vapp(path, &bundleId, &version, &user);
            } else {
                if (vapp.versionInfo.prevVersion == vapp.versionInfo.version) {
                    version = vapp.versionInfo.version;
                    result = oaa_reinstall_vapp(path, &bundleId, &version);
                } else {
                    version = vapp.versionInfo.prevVersion;
                    result = oaa_upgrade_vapp(path, bundleId, &version);
                }
            }
            NSLog(@"Install: res:%d", result);
            if (result == oaaErrSuccess) {
                vapp.userInfo.user = user;
                vapp.bundleId = bundleId;
                vapp.versionInfo.version = version;
                vapp.progress = 1.0;
                [self saveStatus:WBVappStatusInstalled forVApp:vapp];
                [WBEventManager logVappInstallResultEvent:vapp result:@"0" timeCost:(NSInteger)(CFAbsoluteTimeGetCurrent()-start)];
            } else {
                vapp.progress = 0.0;
                PostNotificationOnMainThread(WBVAppInstallErrorNotification, vapp);
                [self saveStatus:WBVappStatusInstallError forVApp:vapp];
                NSString *errorMsg = [self errorMessageForOAAErr:result];
                [[WBVAppManager sharedManager] saveError:WBVappStatusInstallError
                                             errorDomain:WBErrorDomainVAppOAA
                                              errorCode:result
                                           errorMessage:errorMsg
                                               forVApp:vapp];
                [WBEventManager logVappInstallResultEvent:vapp result:errorMsg timeCost:(NSInteger)(CFAbsoluteTimeGetCurrent()-start)];
            }

            // Start downloading vapp resources, which may include bytecodes and other optional resources.
            if (![WBStorageManager.sharedManager hasRes:vapp ofSha1Hash:vapp.versionInfo.resHash]) {
                if ([[vapp.versionInfo.resURL lowercaseString] hasPrefix:@"http"]) {
                    [WBVAppResDownloadManager.sharedManager addToDownloadQueue:vapp];
                } else {
                    [self saveStatus:WBVappStatusResourceDownloadGiveUp forVApp:vapp];
                }
            } else {
                [self saveStatus:WBVappStatusResourceDownloaded forVApp:vapp];
                [[WBStorageManager sharedManager] unzipRes:vapp];
            }

        } else {
            PostNotificationOnMainThread(WBVAppInstallErrorNotification, vapp);
            [self saveStatus:WBVappStatusInstallError forVApp:vapp];
            [self saveError:WBVappStatusInstallError
                errorDomain:error.domain
                  errorCode:error.code
               errorMessage:error.localizedDescription
                    forVApp:vapp];
            [WBEventManager logVappInstallResultEvent:vapp result:error.localizedDescription timeCost:(NSInteger)(CFAbsoluteTimeGetCurrent()-start)];
        }
    }];
}

- (void)initVApp:(WBVAppModel *)vapp resPath:(NSString *)resPath callback:(void (^)(void))callbackHandler {
    if (vapp.status == WBVappStatusIniting || vapp.status == WBVappStatusInited || vapp.status == WBVappStatusResourceInstallError) {
        if (callbackHandler) callbackHandler();
        return;
    }
    [self saveStatus:WBVappStatusIniting forVApp:vapp];
    CFAbsoluteTime start = CFAbsoluteTimeGetCurrent();
    [WBEventManager logVappInitEvent:vapp];

    // 更新应用资源
    OAAErr errCode = oaa_update_vapp_res(vapp.bundleId, vapp.versionInfo.version, resPath);
    if (errCode != oaaErrSuccess) {
        NSString *errorMsg = [self errorMessageForOAAErr:errCode];
        [[WBVAppManager sharedManager] saveError:WBVappStatusInitError
                                     errorDomain:WBErrorDomainVAppOAA
                                      errorCode:errCode
                                   errorMessage:errorMsg
                                       forVApp:vapp];
        [self saveStatus:WBVappStatusInitError forVApp:vapp];
        [WBEventManager logVappInitResultEvent:vapp result:errorMsg timeCost:(NSInteger)(CFAbsoluteTimeGetCurrent()-start)];
        if (callbackHandler) callbackHandler();
        return;
    }

    // 初始化应用
    errCode = oaa_init_vapp(vapp.bundleId, vapp.versionInfo.version, resPath);
    if (errCode == oaaErrSuccess) {
        [self saveStatus:WBVappStatusInited forVApp:vapp];
        [WBEventManager logVappInitResultEvent:vapp result:@"0" timeCost:(NSInteger)(CFAbsoluteTimeGetCurrent()-start)];
    } else {
        NSString *errorMsg = [self errorMessageForOAAErr:errCode];
        [[WBVAppManager sharedManager] saveError:WBVappStatusInitError
                                     errorDomain:WBErrorDomainVAppOAA
                                      errorCode:errCode
                                   errorMessage:errorMsg
                                       forVApp:vapp];
        [self saveStatus:WBVappStatusInitError forVApp:vapp];
        [WBEventManager logVappInitResultEvent:vapp result:errorMsg timeCost:(NSInteger)(CFAbsoluteTimeGetCurrent()-start)];
    }
    if (callbackHandler) callbackHandler();
}

