	for (WBRichMessageLinkModel *model in arrayModel) {
		NSDictionary *dict = [model convertToDict];
		[arrayDict addObject:dict];
	}
	return [arrayDict copy];
}

- (instancetype)initWithDict:(NSDictionary *)dict sourceInterface:(nullable NSString *)sourceInterface {
    self.sourceInterface = sourceInterface;
    if (self = [super init]) {
        id type = dict[@"type"] ?: dict[@"operation"];
        //        NSParameterAssert([type isKindOfClass:[NSNumber class]]);
        int tempType = [type intValue];
        if (tempType > 0) { // type = -1 就要去找 banner 的 operation
            self.type = tempType;
        } else {
            id operation = dict[@"operation"];
            self.type = [operation intValue];
        }
        self.label = dict[@"label"];
        self.imageURL = dict[@"image"];
        self.iconURL = dict[@"icon"];

//        NSParameterAssert([dict[@"link"] isKindOfClass:[NSString class]]);
        self.link = dict[@"link"];
        self.richMessageLinkId = [dict[@"id"] stringValue];
        self.bannerId = [dict[@"bannerId"] stringValue];

        id style = dict[@"style"];
        if (style) {
            NSParameterAssert([style isKindOfClass:[NSNumber class]]);
            self.style = [style intValue];
        }

        self.timeout = [dict[@"timeout"] floatValue];
        NSNumber *dismissOnTap = dict[@"dismiss"];
        self.dismissOnTap = dismissOnTap ? [dismissOnTap boolValue] : true;
        [self initGeneralAction];
    }
    return self;
}

- (NSDictionary *)convertToDict {
	return @{
		@"type": [NSNumber numberWithInt:self.type],
		@"label": self.label ?: [NSNull null],
		@"image": self.imageURL ?: [NSNull null],
		@"icon": self.iconURL ?: [NSNull null],
		@"link": self.link ?: [NSNull null],
		@"style": [NSNumber numberWithInt:self.style],
		@"timeout": [NSNumber numberWithFloat:self.timeout],
		@"dismiss": [NSNumber numberWithBool:self.isDismissOnTap]
	};
}

- (void)setType:(WBRichMessageLinkType)type {
    _type = type;
    [self initGeneralAction];
}

- (void)initGeneralAction {
    @weakify(self)
    switch(self.type) {
        case WBRichMessageLinkTypeFAQ:
            // no general action, since action's supported in Support page only
            break;
        case WBRichMessageLinkTypeArticle:
            // no general action, since needs a navigationVC
            break;
        case WBRichMessageLinkTypeWebview:
            if (_generalAction == nil) {
                _generalAction = ^{
                    @strongify(self)
                    [WBAppManager.sharedManager showInWebView:self.link];
                };
            }
            break;
        case WBRichMessageLinkTypeAppstoreRate:
            // no general action, since source's required to rate
            break;
        case WBRichMessageLinkTypeAppstoreInfo:
            if (_generalAction == nil) {
                _generalAction = ^{
                    @strongify(self)
                    [WBAppManager.sharedManager viewAppDetailInAppStore:self.link];
                };
            }
            break;
        case WBRichMessageLinkTypeAppstoreSearch:
            if (_generalAction == nil) {
                _generalAction = ^{
                    @strongify(self)
                    [WBAppManager.sharedManager searchInAppStore:self.link];
                };
            }
            break;
        case WBRichMessageLinkTypeSafari:
            if (_generalAction == nil) {
                _generalAction = ^{
                    @strongify(self)
                    [WBAppManager.sharedManager openInSafari:self.link];
                };
            }
            break;
        case WBRichMessageLinkTypeDismiss:
            // no general action, only supported in popup
            break;
        case WBRichMessageLinkTypeExit:
            // no general action, only supported in popup
            break;
        case WBRichMessageLinkTypeWBRoute:
            if (_generalAction == nil) {
                _generalAction = ^{
                    @strongify(self)
                    if (!self.link) return;
                    // 添加对self.link的http或https开头的检查
                    if ([self.link hasPrefix:@"http://"] || [self.link hasPrefix:@"https://"]) {
                        NSLog(@"This is not a route link but a website link!");
                        return;
                    }
                    NSURL *url = [NSURL URLWithString:self.link];
                    NSString *triggerId = self.richMessageLinkId ?: (self.bannerId ?: nil);
                    if ([url.absoluteString isEqualToString:@"webox:///page/vip"] && triggerId) {
                        NSURLComponents *components = [NSURLComponents componentsWithString:url.absoluteString];
                        NSMutableArray<NSURLQueryItem *> *queryItems = [components.queryItems mutableCopy] ?: [NSMutableArray new];
                        NSURLQueryItem *triggerItem = [NSURLQueryItem queryItemWithName:@"triggerId" value:triggerId];
                        [queryItems addObject:triggerItem];
                        if (!self.richMessageLinkId && self.bannerId) {
                            NSURLQueryItem *sourceItem = [NSURLQueryItem queryItemWithName:@"source" value:@"banner"];
                            [queryItems addObject:sourceItem];
                        }
                        components.queryItems = queryItems;
                        url = components.URL;
                    }
                    dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(0.3 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
                        [[WBRouteManager sharedManager] performRoute:url sourceInterface:self.sourceInterface];
                    });
                };
            }
            break;
        default:
            break;
    }
}

@end

