@implementation NSDictionary (WBExtension)

- (NSString *)wb_URLEncodedString {
    NSMutableString *result = [NSMutableString string];
    NSArray *allKeys = self.allKeys;
    NSInteger keyValueCount = allKeys.count;
    for (NSInteger i = 0; i < keyValueCount; i++) {
        NSString *key = allKeys[i];
        id value = [self valueForKey:key];
        NSString *valueString;
        if ([value isKindOfClass:[NSString class]]) {
            valueString = value;
        } else if ([value isKindOfClass:[NSNumber class]]) {
            valueString = [value stringValue];
        } else {
            NSAssert(YES, @"unexpected value type");
        }
        NSString *keyValueString = [NSString stringWithFormat:@"%@=%@", [key stringByURLEncode], [valueString stringByURLEncode]];
        [result appendString:keyValueString];
        if (i != keyValueCount - 1) {
            [result appendString:@"&"];
        }
    }
    return result;
}

- (NSData *)wb_URLEncodedData {
    return [self.wb_URLEncodedString dataUsingEncoding:NSUTF8StringEncoding];
}

- (NSData *)wb_JSONData {
    NSError *serializeError = nil;
    NSData *data = [NSJSONSerialization dataWithJSONObject:self options:NSJSONWritingPrettyPrinted error:&serializeError];
    NSAssert(serializeError == nil, @"serialize error");
    return data;
}

