- (void)makeActionBackgroundModeOn:(BOOL)isTurnOn switchButton:(UISwitch * _Nullable)switchButton {
    NSParameterAssert(switchButton != nil);
    BOOL isTurningOn = !self.vapp.featureStatusInfo.isNotificationSwitchOn;

    // 封装开关操作的核心逻辑
    void (^toggleNotificationBlock)(BOOL) = ^(BOOL enable) {
        [WBNetworkManager.defaultManager connectNotification:self.vapp.bundleId isOn:!enable callback:^(id _Nullable json, NSError *_Nullable error) {
            dispatch_async(dispatch_get_main_queue(), ^{
                if (error) {
                    self.vapp.featureStatusInfo.isNotificationSwitchOn = !enable;
                    [WBVAppManager.sharedManager saveBackgroundSetting:!enable forVApp:self.vapp];
                    [SVProgressHUD showErrorWithStatus:error.localizedDescription];
                    return;
                } else {
                    id canOn = json[@"canOn"];
                    id tip = json[@"tip"];
                    id route = json[@"route"];
                    if (!canOn || [canOn isKindOfClass:[NSNull class]]) {
                        return;
                    }
                    NSInteger canOnNumber = [(NSNumber *)canOn integerValue];
                    self.vapp.featureStatusInfo.isNotificationSwitchOn = (canOnNumber != 0);
                    [WBVAppManager.sharedManager saveBackgroundSetting:self.vapp.featureStatusInfo.isNotificationSwitchOn forVApp:self.vapp];
                    [switchButton setOn:self.vapp.featureStatusInfo.isNotificationSwitchOn animated:YES];


                    if (tip && ![tip isKindOfClass:[NSNull class]]) {
                        NSString *tipString = [tip stringValue];
                        if (tipString && [tipString stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceCharacterSet]].length > 0) {
                            if (canOnNumber == 0) {
                                [SVProgressHUD showErrorWithStatus:tipString];
                            } else {
                                [SVProgressHUD showSuccessWithStatus:tipString];
                            }
                        }
                    }

                    if (route && ![route isKindOfClass:[NSNull class]] && [route isKindOfClass:[NSString class]]) {
                        NSURL *routeUrl = [NSURL URLWithString:(NSString *)route];
                        [[WBRouteManager sharedManager] performRoute:routeUrl sourceInterface:@"user/notifyConnect"];
                    }
                }
            });
        }];
    };

    // 封装开启操作的弹窗
    void (^showEnableAlert)(void (^)(void)) = ^(void (^confirmAction)(void)) {
        UIAlertController *alert = [UIAlertController alertControllerWithTitle:@"温馨提醒"
                                                                      message:@"开启消息推送之后可能会加快手机电池消耗，请酌情使用"
                                                               preferredStyle:UIAlertControllerStyleAlert];
        [alert addAction:[UIAlertAction actionWithTitle:@"取消" style:UIAlertActionStyleCancel handler:^(UIAlertAction * _Nonnull action) {
            self.vapp.featureStatusInfo.isNotificationSwitchOn = NO;
            [switchButton setOn:NO animated:YES];
        }]];
        [alert addAction:[UIAlertAction actionWithTitle:@"继续开启"
                                                  style:UIAlertActionStyleDefault
                                                handler:^(UIAlertAction * _Nonnull action) { confirmAction(); }]];
        [[WBAppManager getUIApplicationRootViewController] presentViewController:alert animated:YES completion:nil];
    };

    // 封装关闭操作的弹窗
    void (^showDisableAlert)(void (^)(void)) = ^(void (^confirmAction)(void)) {
        UIAlertController *alert = [UIAlertController alertControllerWithTitle:@"是否关闭消息推送"
                                                                      message:@"关闭后将出现短暂延迟，请稍候"
                                                               preferredStyle:UIAlertControllerStyleAlert];
        [alert addAction:[UIAlertAction actionWithTitle:@"取消" style:UIAlertActionStyleCancel handler:^(UIAlertAction * _Nonnull action) {
            self.vapp.featureStatusInfo.isNotificationSwitchOn = YES;
            [switchButton setOn:YES animated:YES];
        }]];
        [alert addAction:[UIAlertAction actionWithTitle:@"关闭"
                                                  style:UIAlertActionStyleDestructive
                                                handler:^(UIAlertAction * _Nonnull action) { confirmAction(); }]];
        [[WBAppManager getUIApplicationRootViewController] presentViewController:alert animated:YES completion:nil];
    };

    // 密码验证分支处理
    if (self.vapp.featureStatusInfo.isLockSwitchOn) {
        [self showVerifyPasswordView:^{
            if (isTurningOn) {
                showEnableAlert(^{ toggleNotificationBlock(YES); });
            } else {
                showDisableAlert(^{ toggleNotificationBlock(NO); });
            }
        } failBlock:^{
            [switchButton setOn:!isTurningOn animated:YES];
        } vapp:self.vapp];
    } else {
        if (isTurningOn) {
            showEnableAlert(^{ toggleNotificationBlock(YES); });
        } else {
            showDisableAlert(^{ toggleNotificationBlock(NO); });
        }
    }
}

- (void)showVerifyPasswordView:(void(^)(void))successBlock failBlock:(void(^)(void))failBlock vapp:(WBVAppModel *)vapp {
    WBPasswordViewController *passwordVc = [WBPasswordViewController new];
    passwordVc.firstSet = FALSE;
    passwordVc.vapp = vapp;
    passwordVc.type = WBPasswordViewControllerTypeEntry;
    passwordVc.successBlock = successBlock;
    passwordVc.failBlock = failBlock;
    [self.navigationController pushViewController:passwordVc animated:YES];
}

- (void)makeObserveTerminateOn:(BOOL)isTurnOn switchButton:(UISwitch * _Nullable)switchButton {
    NSParameterAssert(switchButton != nil);
    if (switchButton.isOn != isTurnOn) {
        [switchButton setOn:isTurnOn];
    }
    if (isTurnOn) {
        [WBVAppManager.sharedManager saveObserveTerminateSetting:YES forVApp:self.vapp];
        [SVProgressHUD showSuccessWithStatus:@"已开启掉线提醒"];
        [switchButton setOn:YES];
    } else {
        UIAlertController *alertVc = [UIAlertController alertControllerWithTitle:@"温馨提醒" message:@"关闭后台掉线提醒之后可能不能及时收到通知，请酌情使用" preferredStyle:UIAlertControllerStyleAlert];
        [alertVc addAction:[UIAlertAction actionWithTitle:@"取消" style:UIAlertActionStyleDefault handler:^(UIAlertAction * _Nonnull action) {
            [switchButton setOn:YES];
        }]];
        [alertVc addAction:[UIAlertAction actionWithTitle:@"继续关闭" style:UIAlertActionStyleDefault handler:^(UIAlertAction * _Nonnull action) {
            [WBVAppManager.sharedManager saveObserveTerminateSetting:NO forVApp:self.vapp];
            [SVProgressHUD showSuccessWithStatus:@"已关闭掉线提醒"];
            [switchButton setOn:NO];
        }]];
        [[WBAppManager getUIApplicationRootViewController] presentViewController:alertVc animated:YES completion:nil];
    }
}

-(void)onActionMigrateData: (WBVAppModel*)vapp{
    WBImportDataViewController *dataMigrateVC = [WBImportDataViewController new];
    dataMigrateVC.vapp = vapp;
    [self.navigationController pushViewController:dataMigrateVC animated:YES];
}

- (void)onActionBackgroundMode:(id)sender {
    if([sender isKindOfClass:[WBSettingSwitchCell class]]) {
        WBSettingSwitchCell *cell = (WBSettingSwitchCell*)sender;
        [self makeActionBackgroundModeOn:cell.wb_switch.isOn switchButton:cell.wb_switch];
    }
}

- (void)onActionObserveTerminate:(id)sender {
    if([sender isKindOfClass:[WBSettingSwitchCell class]]) {
        WBSettingSwitchCell *cell = (WBSettingSwitchCell*)sender;
        [self makeObserveTerminateOn:cell.wb_switch.isOn switchButton:cell.wb_switch];
    }
}

- (void)vipCheckedFeatureWithSuccessBlock: (void(^)(void))successBlock confirmBlock:(void(^)(void))confirmBlock cancelBlock:(void(^)(void))cancelBlock benefitType:(WBUserBenefit)benefitType {
    BOOL couldUse = false;
    if (benefitType == WBUserBenefitNotification) {
        couldUse = (WBSettingManager.sharedManager.Benefit & WBUserBenefitNotification) != 0;
    } else if (benefitType == WBUserBenefitLock) {
        couldUse = (WBSettingManager.sharedManager.Benefit & WBUserBenefitLock) != 0;
    } else if (benefitType == WBUserBenefitDisguise) {
        couldUse = (WBSettingManager.sharedManager.Benefit & WBUserBenefitDisguise) != 0;
    } else if (benefitType == WBUserBenefitPretense) {
        couldUse = (WBSettingManager.sharedManager.Benefit & WBUserBenefitPretense) != 0;
    }

    if (couldUse) {
        if (successBlock) successBlock();
    } else {
        [WBAlertPopViewController alertWithTitle:@"温馨提示" content:@"该功能为会员专享，开通会员即可解锁" keyWords:nil confirmText:@"立即开通" cancelText:@"我再想想" confirmAction:^{
            if (confirmBlock) confirmBlock();
            [WBMainViewController presentVipPageFromPageSource:@"noti"];
        } cancelAction:^{
            if (cancelBlock) cancelBlock();
        }];
    }
}

- (void)vipCheckedFeatureWithSuccessBlock: (void(^)(void))successBlock cancelBlock:(void(^)(void))cancelBlock benefitType:(WBUserBenefit)benefitType {
    [self vipCheckedFeatureWithSuccessBlock:successBlock confirmBlock:nil cancelBlock:cancelBlock benefitType:benefitType];
}

#pragma mark - Lazy load

- (LAContext *)bioContext {
    if (!_bioContext) {
        _bioContext = [[LAContext alloc] init];
        NSError *err = nil;
        if (![_bioContext canEvaluatePolicy:LAPolicyDeviceOwnerAuthenticationWithBiometrics error:&err]) {
            NSLog(@"%@", err);
        }
    }
    return _bioContext;
}


