    return self;
}

- (void)initializeChatDatabase {
    _databaseQueue = dispatch_queue_create("com.webox.sqlite.queue", DISPATCH_QUEUE_SERIAL);

    dispatch_sync(_databaseQueue, ^{
        _chatDBPath = [self.docRoot stringByAppendingPathComponent:[WBUtility getCodeNameSaltedSha1Hash:kAIChatsSqlite]];

        if (sqlite3_open(self.chatDBPath.UTF8String, &_chatDatabase) != SQLITE_OK) {
            NSLog(@"Failed to open chat database");
            return;
        }

        // 创建会话表
        const char *createSessionTableSQL = "CREATE TABLE IF NOT EXISTS sessions ("
                                            "id TEXT PRIMARY KEY,"
                                            "agent_name TEXT NOT NULL,"
                                            "created_at DATETIME DEFAULT CURRENT_TIMESTAMP,"
                                            "latest_message TEXT);";

        // 创建消息表
        const char *createMessageTableSQL = "CREATE TABLE IF NOT EXISTS messages ("
                                            "id TEXT PRIMARY KEY,"
                                            "session_id TEXT NOT NULL,"
                                            "content TEXT NOT NULL,"
                                            "is_sender BOOLEAN NOT NULL,"
                                            "timestamp DATETIME DEFAULT CURRENT_TIMESTAMP,"
                                            "done BOOLEAN DEFAULT 0,"
                                            "context TEXT,"
                                            "FOREIGN KEY(session_id) REFERENCES sessions(id) ON DELETE CASCADE);";

        char *errorMsg;
        if (sqlite3_exec(_chatDatabase, createSessionTableSQL, NULL, NULL, &errorMsg) != SQLITE_OK) {
            NSLog(@"Failed to create sessions table: %s", errorMsg);
            sqlite3_free(errorMsg);
        }

        if (sqlite3_exec(_chatDatabase, createMessageTableSQL, NULL, NULL, &errorMsg) != SQLITE_OK) {
            NSLog(@"Failed to create messages table: %s", errorMsg);
            sqlite3_free(errorMsg);
        }

        // 启用外键支持
        sqlite3_exec(_chatDatabase, "PRAGMA foreign_keys = ON;", NULL, NULL, NULL);
    });
}

- (void)dealloc {
    if (_chatDatabase) {
        sqlite3_close(_chatDatabase);
        _chatDatabase = nil;
    }
}


#pragma mark - file system version & migration
//
// migrate old app data to new app data, run it in a non-main thread if the migration might take a long time in the future
//
- (void)fileSystemVersionCheck {
    NSInteger currentVersion = WBSettingManager.sharedManager.FileSystemVersion;
    if (currentVersion == fileSystemVersionEmpty) {
        // its a fresh installation OR its an old filesystem with no filesystem version number
        //
        // we identify old filesystem by the existense of file "wb_vapp_status.plist"
        NSString *oldInstalledVAppListFilePath = [NSSearchPathForDirectoriesInDomains(NSDocumentDirectory, NSUserDomainMask, YES).firstObject stringByAppendingPathComponent:@"wb_vapp_status.plist"];
        if ([NSFileManager.defaultManager fileExistsAtPath:oldInstalledVAppListFilePath]) {
            currentVersion = fileSystemVersionClassic;
        }
    }
    if (currentVersion != kNewestFileSystemVersion) {
        [self migrateFrom:currentVersion to:kNewestFileSystemVersion];
        WBSettingManager.sharedManager.FileSystemVersion = kNewestFileSystemVersion;
    }
}


- (void)migrateFrom:(NSInteger)from to:(NSInteger)to{
    while(from != to) {
        switch(from) {
            case fileSystemVersionEmpty:
                return;
            case fileSystemVersionClassic:
                from = [self migrateFromClassicToStorageManager];
            case fileSystemVersionWithStorageManager:
                return;
            default:
                NSAssert(false, @"invalid file system version");
                return;
        }
    }
}
- (NSInteger)migrateFromClassicToStorageManager {
    //
    // wb_vapp_status.plist
    //
    NSString *oldInstalledVAppListFilePath = [NSSearchPathForDirectoriesInDomains(NSDocumentDirectory, NSUserDomainMask, YES).firstObject stringByAppendingPathComponent:@"wb_vapp_status.plist"];
    NSArray *jsonArray = [NSArray arrayWithContentsOfFile:oldInstalledVAppListFilePath];
    NSMutableArray *newJsonArray = [[NSMutableArray alloc] init];
    for(NSDictionary* dic in jsonArray) {
        NSMutableDictionary *newObj = [[NSMutableDictionary alloc] init];
        newObj[@"vid"] = dic[@"id"];
        newObj[@"name"] = dic[@"name"];
        newObj[@"trackId"] = nil;
        newObj[@"bundleId"] = dic[@"bundle_id"];
        newObj[@"iconURL"] = dic[@"icon_url"];
        newObj[@"subtitle"] = nil;
        newObj[@"artistName"] = nil;
        newObj[@"reserveCount"] = dic[@"reserve_count"];
        newObj[@"reserved"] = dic[@"reserved"];
        newObj[@"dual"] = dic[@"dual"];
        newObj[@"isDownload"] = dic[@"isDownload"];
        newObj[@"status"] = dic[@"status"];
        if ([newObj[@"status"] isKindOfClass:[NSNumber class]]) {
            if ([newObj[@"status"] intValue] == 256 || [newObj[@"status"] intValue] == 1024) {
                newObj[@"progress"] = @(1.0);
            }
        }

        NSMutableDictionary *versionObj = [[NSMutableDictionary alloc] init];
        versionObj[@"version"] = dic[@"version"];
        versionObj[@"forceUpdate"] = dic[@"force_update"];
        versionObj[@"desc"] = dic[@"description"];
        versionObj[@"refURL"] = dic[@"ref_url"];
        versionObj[@"ipaURL"] = dic[@"ipa_url"];
        versionObj[@"resURL"] = dic[@"res_url"];
        versionObj[@"ipaSize"] = dic[@"ipa_size"];
        versionObj[@"ipaHash"] = dic[@"ipa_hash"];
        versionObj[@"timeInit"] = dic[@"time_init"];
        versionObj[@"timeLaunch"] = dic[@"time_launch"];
        versionObj[@"ef"] = dic[@"ef"];
        newObj[@"versionInfo"] = versionObj;

        NSMutableDictionary *userObj = [[NSMutableDictionary alloc] init];
        userObj[@"user"] = dic[@"user"];
        userObj[@"password"] = dic[@"password"];
        userObj[@"customName"] = dic[@"fakeName"];
        userObj[@"customIcon"] = dic[@"fakeIcon"];
        newObj[@"userInfo"] = userObj;

        [newJsonArray addObject:newObj];
    }
    [newJsonArray writeToFile:_installedVAppListFilePath atomically:YES];
    [NSFileManager.defaultManager removeItemAtPath:oldInstalledVAppListFilePath error:nil];
    NSLog(@"wb_vapp_status.plist migrated");

    //
    // token in userdefaults
    //
    NSString *tokenKey = [[NSString alloc] initWithFormat:@"_%@_Token", ABBridge_GetAppCodeName()];
    NSString *token = [[NSUserDefaults standardUserDefaults] stringForKey:tokenKey];
    if (token) {
        WBSettingManager.sharedManager.Token = token;
        [[NSUserDefaults standardUserDefaults] setObject:nil forKey:tokenKey];
        NSLog(@"token migrated");
    }

