- (void)loadHotReservedAppsWithCallback:(VAppsDataLoadCallback)callback {
    if (self.hotReservedApps) {
        if (callback) callback(self.hotReservedApps, TRUE);
    } else {
        [WBNetworkManager.defaultManager getHotReservesWithCount:NSIntegerMax callback:^(NSArray<WBVAppBaseHttpModel *> * _Nullable vApps, NSError * _Nullable error) {
            if (error) {
                if (callback) callback(nil, FALSE);
            } else {
                self.hotReservedApps = [self parseVAppHttpModelList:vApps];
                if (callback) callback(self.hotReservedApps, TRUE);
            }
        }];
    }
}

- (void)loadDualAppsWithCallback:(VAppsDataLoadCallback)callback {
    if (self.dualApps) {
        if (callback) callback(self.dualApps, TRUE);
    } else {
        [WBNetworkManager.defaultManager getDualVAppsWithCount:NSIntegerMax callback:^(NSArray<WBVAppBaseHttpModel *> * _Nullable vApps, NSError * _Nullable error) {
            if (error) {
                if (callback) callback(nil, FALSE);
            } else {
                self.dualApps = [self parseVAppHttpModelList:vApps];
                for(WBVAppModel* vapp in self.dualApps) {
                    vapp.dual = TRUE;
                    vapp.isDownload = NO;
                }

                NSMutableSet *downloadedIDs = [NSMutableSet set];
                for (WBVAppModel *app in self.myApps) {
                    [downloadedIDs addObject:@(app.vid)];
                }
                for (WBVAppModel *app in self.dualApps) {
                    app.isDownload = [downloadedIDs containsObject:@(app.vid)]; // 转为同类型比较
                }
                if (callback) callback(self.dualApps, TRUE);
            }
        }];
    }
}

- (void)loadHotAppsWithCallback:(VAppsDataLoadCallback)callback {
    if (self.hotApps) {
        if (callback) callback(self.hotApps, TRUE);
    } else {
        [WBNetworkManager.defaultManager getHotVAppsWithCount:20 callback:^(NSArray<WBVAppBaseHttpModel *> * _Nullable vApps, NSError * _Nullable error) {
            if (error) {
                if (callback) callback(nil, FALSE);
            } else {
                self.hotApps = [self parseVAppHttpModelList:vApps];
                if (callback) callback(self.hotApps, TRUE);
            }
        }];
    }
}

- (void)loadMyReservedAppsWithCallback:(VAppsDataLoadCallback)callback {
    if (self.myReservedApps) {
        if (callback) callback(self.myReservedApps, TRUE);
    } else {
        [WBNetworkManager.defaultManager getMyReservesWithCount:NSIntegerMax callback:^(NSArray<WBVAppBaseHttpModel *> * _Nullable vApps, NSError * _Nullable error) {
