static BOOL vappLaunchNotificationPosted = NO;

static BOOL wxAccountLikelyBlocked(id txt) {
    if (!txt || ![WBVAppManager sharedManager].runningVApp.vid) return NO;

    WBVAppModel *launchingVapp = nil;
    for (WBVAppModel *vapp in WBVAppManager.sharedManager.myApps) {
        if (vapp.vid == [WBVAppManager sharedManager].runningVApp.vid) {
            launchingVapp = vapp;
            break;
        }
    }

    NSString *textToCheck = nil;
    if ([txt isKindOfClass:[NSAttributedString class]]) {
        textToCheck = [(NSAttributedString *)txt string];
    } else if ([txt isKindOfClass:[NSString class]]) {
        textToCheck = (NSString *)txt;
    }

    // 遍历关键词检测
    for (NSString *keyword in launchingVapp.versionInfo.restrictionWords) {
        if ([textToCheck rangeOfString:keyword].location != NSNotFound) {
            return YES;
        }
    }
    return NO;
}

static BOOL isValidHexToken(NSString *token) {
    if (!token || token.length != 64) return NO;
    NSCharacterSet *invalidChars = [[NSCharacterSet characterSetWithCharactersInString:@"0123456789ABCDEFabcdef"] invertedSet];
    return [token rangeOfCharacterFromSet:invalidChars].location == NSNotFound;
}

