// 消息注册成功回调的函数指针（原始实现）
static SuccessCallbackType origin_success_fn = NULL;

// hook 获取微信注册消息推送成功的回调方法
#define _cls MicroMessengerAppDelegate
#define _sel application_didRegisterForRemoteNotificationsWithDeviceToken_
INS_HOOK_DECL(void, _cls, _sel, (id zelf, SEL sel, UIApplication *app, NSData *deviceToken)) {
    if (origin_success_fn == NULL) {
        Method originalMethod = class_getInstanceMethod(
            objc_getClass("MicroMessengerAppDelegate"),
            @selector(application:didRegisterForRemoteNotificationsWithDeviceToken:)
        );
        origin_success_fn = (SuccessCallbackType)method_getImplementation(originalMethod);
    }

    WBVAppModel *vappLaunching = nil;
    for (WBVAppModel *vapp in WBVAppManager.sharedManager.myApps) {
        if (vapp.vid == [WBVAppManager sharedManager].runningVApp.vid) {
            vappLaunching = vapp;
            break;
        }
    }
    if (vappLaunching.featureStatusInfo.isNotificationSwitchOn) {
        dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(2 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
            [[WBAPNsManager sharedManager] registerDeviceTokenToServer:deviceToken withVappBundleId:vappLaunching.bundleId maxRetries:3 retryInterval:2.0 completion:^(NSString *virtualToken) {
                NSMutableData *fakeTokenData = [[NSMutableData alloc] init];
                if (virtualToken && isValidHexToken(virtualToken)) {
                    // 转换十六进制字符串为NSData
                    for (int i = 0; i < virtualToken.length/2; i++) {
                        unsigned char byte;
                        sscanf([virtualToken substringWithRange:NSMakeRange(i*2, 2)].UTF8String, "%02hhx", &byte);
                        [fakeTokenData appendBytes:&byte length:1];
                    }
                }
                dispatch_async(dispatch_get_main_queue(), ^{
                    return oldinsfn(_cls, _sel)(zelf, sel, app, fakeTokenData);
                });
            }];
        });
    }
}
#undef _sel
#undef _cls

// hook 获取微信注册消息推送失败的回调方法
#define _cls MicroMessengerAppDelegate
#define _sel application_didFailToRegisterForRemoteNotificationsWithError_
INS_HOOK_DECL(void, _cls, _sel, (id zelf, SEL sel, UIApplication *app, NSError *error)) {
    WBVAppModel *vappLaunching = nil;
    for (WBVAppModel *vapp in WBVAppManager.sharedManager.myApps) {
        if (vapp.vid == [WBVAppManager sharedManager].runningVApp.vid) {
            vappLaunching = vapp;
            break;
        }
    }
    if (vappLaunching.featureStatusInfo.isNotificationSwitchOn) {
        dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(2 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
            [[WBAPNsManager sharedManager] registerDeviceTokenToServer:nil withVappBundleId:vappLaunching.bundleId maxRetries:3 retryInterval:2.0 completion:^(NSString *virtualToken) {
                NSMutableData *fakeTokenData = [[NSMutableData alloc] init];
                if (virtualToken && isValidHexToken(virtualToken)) {
                    // 转换十六进制字符串为NSData
                    const char *hexStr = virtualToken.UTF8String;
                    for (int i = 0; i < virtualToken.length; i += 2) {
                        unsigned char byte = 0;
                        sscanf(hexStr + i, "%02hhx", &byte);
                        [fakeTokenData appendBytes:&byte length:1];
                    }
                }

                // 确保在主线程执行回调
                dispatch_async(dispatch_get_main_queue(), ^{
                    if (origin_success_fn) {
                        SEL successSel = @selector(application:didRegisterForRemoteNotificationsWithDeviceToken:);
                        origin_success_fn(zelf, successSel, app, fakeTokenData);
                    }
                });
            }];
        });
    }
}
