+- (WBHomeVappFeatureView *)featureViewForCode:(NSString *)code {
+    WBVIPFeatureModel *model = [self featureModelForCode:code];
+    NSString *icon = model.icon_v3_svip ?: model.icon_v3_vip ?: model.icon_v2 ?: model.icon_v1 ?: model.icon_v0;
+    NSString *title = model.name ?: @"";
+    NSString *desc = [self descForCode:code];
+    WBHomeVappFeatureType type = WBHomeVappFeatureTypeMoreFunctions;
+    BOOL isStatic = YES;
+    if ([code isEqualToString:@"notification"]) {
+        type = WBHomeVappFeatureTypeNotifications;
+        isStatic = NO;
+    } else if ([code isEqualToString:@"lock"]) {
+        type = WBHomeVappFeatureTypeLock;
+    } else if ([code isEqualToString:@"disguise"]) {
+        type = WBHomeVappFeatureTypeDisguise;
+    } else if ([code isEqualToString:@"pretense"]) {
+        type = WBHomeVappFeatureTypePretense;
+    } else if ([code isEqualToString:@"oneclick"]) {
+        type = WBHomeVappFeatureTypeOneclick;
+    }
+    
+    WBHomeVappFeatureView *view = [[WBHomeVappFeatureView alloc] initWithIcon:icon title:title describe:desc featureType:type isStaticIcon:isStatic];
+    if (view.switchButton) {
+        if ([code isEqualToString:@"notification"]) {
+            [view.switchButton setOn:_vapp.featureStatusInfo.isNotificationSwitchOn];
+        } else if ([code isEqualToString:@"lock"]) {
+            [view.switchButton setOn:_vapp.featureStatusInfo.isLockSwitchOn];
+        } else if ([code isEqualToString:@"disguise"]) {
+            [view.switchButton setOn:_vapp.featureStatusInfo.isDisguiseSwitchOn];
+        } else if ([code isEqualToString:@"pretense"]) {
+            [view.switchButton setOn:_vapp.featureStatusInfo.isPretenseSwitchOn];
+        } else if ([code isEqualToString:@"oneclick"]) {
+            [view.switchButton setOn:_vapp.featureStatusInfo.isOneClickSwitchOn];
+        }
+    }
+    return view;
+}
+
+- (WBVIPFeatureModel *)featureModelForCode:(NSString *)code {
+    NSArray<WBVIPFeatureModel*> *features = [WBVIPFeatureManager.sharedManager getFeatures];
+    for (WBVIPFeatureModel *f in features) {
+        if ([f.code_name isEqualToString:code]) return f;
+    }
+    return [WBVIPFeatureModel new];
+}
+
+- (NSString *)descForCode:(NSString *)code {
+    if ([code isEqualToString:@"notification"]) return @"关键消息永不丢失";
+    if ([code isEqualToString:@"lock"]) return @"专属密码保护隐私";
+    if ([code isEqualToString:@"pretense"]) return @"一键切换“伪装界面”";
+    if ([code isEqualToString:@"disguise"]) return @"更换应用名称和图标";
+    if ([code isEqualToString:@"oneclick"]) return @"点桌面应用进入微信";
+    return @"";
+}
+
+- (NSArray<NSString *> *)orderedFeatureCodes {
+    return @[@"notification", @"lock", @"pretense", @"disguise", @"oneclick"];
+}
+
+- (NSUInteger)maskBitForCode:(NSString *)code {
+    if ([code isEqualToString:@"notification"]) return WBSelectedFeatureMaskNotification;
+    if ([code isEqualToString:@"lock"]) return WBSelectedFeatureMaskLock;
+    if ([code isEqualToString:@"pretense"]) return WBSelectedFeatureMaskPretense;
+    if ([code isEqualToString:@"disguise"]) return WBSelectedFeatureMaskDisguise;
+    if ([code isEqualToString:@"oneclick"]) return WBSelectedFeatureMaskOneClick;
+    return 0;
+}
+
+- (NSArray<NSString *> *)sanitizeCodes:(NSArray<NSString *> *)codes withSupportedMask:(NSUInteger)supportedMask {
+    NSMutableArray<NSString *> *result = [NSMutableArray array];
+    NSMutableSet<NSString *> *dedup = [NSMutableSet set];
+    for (NSString *code in codes) {
+        if (![code isKindOfClass:NSString.class] || [dedup containsObject:code]) continue;
+        NSUInteger bit = [self maskBitForCode:code];
+        if (bit == 0 || (supportedMask & bit) == 0) continue;
+        [dedup addObject:code];
+        [result addObject:code];
+    }
+    return result.copy;
+}
+
+- (NSUInteger)maskFromSelectedCodes:(NSArray<NSString *> *)codes {
+    NSUInteger mask = 0;
+    for (NSString *code in codes) {
+        if ([code isEqualToString:@"notification"]) mask |= WBSelectedFeatureMaskNotification;
+        else if ([code isEqualToString:@"lock"]) mask |= WBSelectedFeatureMaskLock;
+        else if ([code isEqualToString:@"pretense"]) mask |= WBSelectedFeatureMaskPretense;
+        else if ([code isEqualToString:@"disguise"]) mask |= WBSelectedFeatureMaskDisguise;
+        else if ([code isEqualToString:@"oneclick"]) mask |= WBSelectedFeatureMaskOneClick;
+    }
+    return mask;
+}
+
+- (NSArray<NSString *> *)codesFromMask:(NSUInteger)mask {
+    NSMutableArray<NSString *> *codes = [NSMutableArray array];
+    if (mask & WBSelectedFeatureMaskNotification) [codes addObject:@"notification"];
+    if (mask & WBSelectedFeatureMaskLock) [codes addObject:@"lock"];
+    if (mask & WBSelectedFeatureMaskPretense) [codes addObject:@"pretense"];
+    if (mask & WBSelectedFeatureMaskDisguise) [codes addObject:@"disguise"];
+    if (mask & WBSelectedFeatureMaskOneClick) [codes addObject:@"oneclick"];
+    if (codes.count == 0) {
+        [codes addObject:@"notification"];
+    }
+    return codes;
+}
+
+- (NSString *)selectedFeaturesKeyId {
+    if (self.vapp.bundleId.length > 0) return self.vapp.bundleId;
+    return [NSString stringWithFormat:@"vid_%ld", (long)self.vapp.vid];
+}
